// ─── Enhanced Quality Scoring (0-100 pts total) ──────────────────────────────
// 7 factors + quality penalties for risk/complications
// Market Trend(15), Valuation(20), Earnings(15), FutureGrowth(15),
// Sentiment(12), Momentum/RSI(13), Analyst(10) = 100
// Then apply penalties for red flags (below SMA, low sentiment, negative growth)
const scoreStock = (stock) => {
  let score = 0;

  // 1. Market Trend — 52W position (0-15 pts)
  //    Sweet spot 30-70% of 52W range
  const range = stock.high52Week - stock.low52Week;
  let marketTrend = 0;
  if (range > 0) {
    const pos = (stock.currentPrice - stock.low52Week) / range;
    if (pos >= 0.3 && pos <= 0.7) marketTrend = 15;
    else if (pos < 0.3) marketTrend = pos * 30;     // near 52W low → lower score
    else marketTrend = (1 - pos) * 30;               // near 52W high → lower score
  } else {
    marketTrend = 7;
  }
  score += marketTrend;

  // 2. Valuation — PE ratio (0-20 pts)
  let valuation = 0;
  if (stock.peRatio && stock.peRatio > 0) {
    if      (stock.peRatio < 15) valuation = 20;
    else if (stock.peRatio < 25) valuation = 16;
    else if (stock.peRatio < 40) valuation = 11;
    else if (stock.peRatio < 60) valuation = 6;
    else                         valuation = 2;
  } else {
    valuation = 8;   // no PE data → neutral
  }
  score += valuation;

  // 3. Earnings Growth (0-15 pts)
  const eg = stock.earningsGrowth ?? 0;
  let earnings = 0;
  if      (eg >= 50) earnings = 15;
  else if (eg >= 25) earnings = 12;
  else if (eg >= 15) earnings = 9;
  else if (eg >= 8)  earnings = 6;
  else if (eg >= 0)  earnings = 3;
  else               earnings = 0;   // negative growth = 0 pts
  score += earnings;

  // 4. Future Growth / Analyst Target (0-15 pts)
  //    futureGrowth is 0-10 based on analyst target upside
  const fg = stock.futureGrowth ?? 5;
  const futureGrowthScore = Math.min(fg * 1.5, 15);
  score += futureGrowthScore;

  // 5. Sentiment — blended news + momentum (0-12 pts)
  //    Stronger weight: low sentiment now costs more
  const rawSent = stock.socialSentiment ?? 5;
  const sentimentScore = Math.min(rawSent * 1.2, 12);
  score += sentimentScore;

  // 6. Technical Momentum — RSI + SMA signals (0-13 pts)
  let momentum = 6; // default neutral
  const rsi = stock.rsi;
  if (rsi != null) {
    if (rsi >= 30 && rsi <= 50) momentum = 13;       // oversold to fair — best buy zone
    else if (rsi > 50 && rsi <= 60) momentum = 11;   // healthy uptrend
    else if (rsi > 60 && rsi <= 70) momentum = 8;    // moderately extended
    else if (rsi > 70) momentum = 3;                  // overbought — risky
    else if (rsi < 30) momentum = 9;                  // deeply oversold — contrarian
    else momentum = 6;
  }
  // SMA: REWARD above, PENALIZE below
  if (stock.sma50 != null) {
    if (stock.currentPrice > stock.sma50) momentum = Math.min(13, momentum + 1.5);
    else momentum = Math.max(0, momentum - 2);   // PENALTY: below SMA50
  }
  if (stock.sma200 != null) {
    if (stock.currentPrice > stock.sma200) momentum = Math.min(13, momentum + 1.5);
    else momentum = Math.max(0, momentum - 3);   // BIGGER PENALTY: below SMA200 = downtrend
  }
  score += momentum;

  // 7. Analyst Consensus (0-10 pts)
  let analystScore = 5; // default if no data
  const recKey = stock.recommendationKey;
  if (recKey) {
    if (recKey === 'strong_buy') analystScore = 10;
    else if (recKey === 'buy') analystScore = 8;
    else if (recKey === 'hold') analystScore = 5;
    else if (recKey === 'underperform' || recKey === 'sell') analystScore = 2;
    else if (recKey === 'strong_sell') analystScore = 0;
  }
  if (stock.numberOfAnalysts && stock.numberOfAnalysts >= 10) analystScore = Math.min(10, analystScore + 1);
  score += analystScore;

  // ── Quality Penalties (complications filter) ──────────────────────────────
  // Stocks with problems get penalized so they drop in ranking

  // P1: Very low sentiment (< 3) = bearish news / complications → penalty up to -8
  if (rawSent < 3) score -= (3 - rawSent) * 2.5;

  // P2: Negative earnings growth = shrinking profits → penalty up to -5
  if (eg < 0) score -= Math.min(5, Math.abs(eg) * 0.1);

  // P3: No analyst coverage at all → slight penalty (less reliable data)
  if (stock.numberOfAnalysts == null || stock.numberOfAnalysts === 0) score -= 2;

  // P4: Analyst target below current price = analysts see downside → penalty
  if (stock.targetMeanPrice != null && stock.currentPrice > 0) {
    const upside = (stock.targetMeanPrice - stock.currentPrice) / stock.currentPrice;
    if (upside < 0) score -= Math.min(8, Math.abs(upside) * 20); // e.g., -10% target → -2 pts
  }

  // P5: Below BOTH SMA50 and SMA200 = confirmed downtrend → extra penalty
  const belowSma50  = stock.sma50  != null && stock.currentPrice < stock.sma50;
  const belowSma200 = stock.sma200 != null && stock.currentPrice < stock.sma200;
  if (belowSma50 && belowSma200) score -= 5;

  // P6: Extremely high PE (> 80) with low growth = overvalued complication
  if (stock.peRatio > 80 && eg < 20) score -= 4;

  // Floor at 0
  score = Math.max(0, score);

  return {
    total:         Math.round(score * 100) / 100,
    marketTrend:   Math.round(marketTrend        * 100) / 100,
    valuation:     Math.round(valuation          * 100) / 100,
    earnings:      Math.round(earnings           * 100) / 100,
    futureGrowth:  Math.round(futureGrowthScore  * 100) / 100,
    sentiment:     Math.round(sentimentScore     * 100) / 100,
    momentum:      Math.round(momentum           * 100) / 100,
    analyst:       Math.round(analystScore       * 100) / 100,
  };
};

// ─── Compute quality-proportional weights (min 5%, sum = 100%) ────────────────
const computeQualityWeights = (sortedStocks) => {
  const totalScore = sortedStocks.reduce((sum, s) => sum + (s.score || 1), 0);
  let weights = sortedStocks.map(s =>
    totalScore > 0 ? Math.round((s.score / totalScore) * 1000) / 10 : 10
  );
  const MIN_WEIGHT = 5;
  let excess = 0;
  weights = weights.map(w => {
    if (w < MIN_WEIGHT) { excess += MIN_WEIGHT - w; return MIN_WEIGHT; }
    return w;
  });
  if (excess > 0) {
    for (let i = 0; i < weights.length && excess > 0; i++) {
      if (weights[i] > MIN_WEIGHT) {
        const reduction = Math.min(weights[i] - MIN_WEIGHT, excess);
        weights[i] = Math.round((weights[i] - reduction) * 10) / 10;
        excess = Math.round((excess - reduction) * 10) / 10;
      }
    }
  }
  const weightSum = Math.round(weights.reduce((s, w) => s + w, 0) * 10) / 10;
  const diff = Math.round((100 - weightSum) * 10) / 10;
  if (diff !== 0) weights[0] = Math.round((weights[0] + diff) * 10) / 10;
  return weights;
};

// ─── Compute quantity of shares per stock based on quality weight ──────────────
const computeQuantities = (sortedStocks, weights, investmentAmount = 100000) => {
  return sortedStocks.map((stock, idx) => {
    const alloc = (weights[idx] / 100) * investmentAmount;
    const price = stock.currentPrice || 1;
    const qty = Math.max(1, Math.floor(alloc / price));
    return qty;
  });
};

const buildReason = (stock, rank, scores) => {
  const pe = stock.peRatio ? `PE ${stock.peRatio.toFixed(1)}` : 'PE N/A';
  const eg = stock.earningsGrowth != null ? `${stock.earningsGrowth.toFixed(1)}%` : 'N/A';
  const fg = (stock.futureGrowth ?? 5).toFixed(1);
  const sent = (stock.socialSentiment ?? 5).toFixed(1);
  const rsiStr = stock.rsi != null ? ` | RSI ${stock.rsi.toFixed(0)}` : '';
  const analystStr = stock.recommendationKey ? ` | Analyst: ${stock.recommendationKey.toUpperCase()}` : '';
  const targetStr = stock.targetMeanPrice ? ` | Target ₹${Math.round(stock.targetMeanPrice)}` : '';
  return `Rank #${rank} | ${pe} | EPS growth ${eg} | Future ${fg}/10 | Sentiment ${sent}/10${rsiStr}${analystStr}${targetStr}`;
};

const getCategoryFromName = (name) => {
  // Check for US prefix first
  const isUS = name.startsWith('US ');
  const prefix = isUS ? 'usa_' : '';
  if (name.includes('Midcap'))     return prefix + 'midCap';
  if (name.includes('Smallcap'))   return prefix + 'smallCap';
  if (name.includes('Tech'))       return prefix + 'tech';
  if (name.includes('Finance'))    return prefix + 'finance';
  if (name.includes('Healthcare')) return prefix + 'healthcare';
  if (name.includes('Renewable'))  return prefix + 'renewable';
  if (name.includes('Consumer'))   return prefix + 'consumer';
  if (name.includes('Infra'))      return prefix + 'infrastructure';
  if (!isUS) {
    if (name.includes('Auto'))       return 'auto';
    if (name.includes('Metal'))      return 'metals';
    if (name.includes('Telecom'))    return 'telecom';
    if (name.includes('PSU'))        return 'psu';
    if (name.includes('Realty') || name.includes('Real Estate')) return 'realty';
    if (name.includes('Chemical'))   return 'chemicals';
    if (name.includes('Cement'))     return 'cement';
    if (name.includes('Oil') || name.includes('Gas') || name.includes('Energy')) return 'oilgas';
    if (name.includes('Fertil') || name.includes('Agri')) return 'fertilizer';
    if (name.includes('Defence') || name.includes('Defense')) return 'defence';
    if (name.includes('Media') || name.includes('Entertainment')) return 'media';
    if (name.includes('Textile') || name.includes('Apparel')) return 'textile';
    if (name.includes('Undervalued') || name.includes('Value')) return 'undervalued';
    if (name.includes('Micro')) return 'microCap';
  }
  return prefix + 'largeCap';
};

const mergeWithFallback = (universeDefs, liveResults) => {
  return universeDefs.map((def, idx) => {
    const live = liveResults[idx];
    const fallback = STATIC_FALLBACK[def.ticker] || {};

    if (live && live.currentPrice > 0) {
      // Supplement missing fundamentals from static fallback (v8 chart lacks PE/EPS)
      return {
        ...live,
        peRatio:           live.peRatio            ?? fallback.peRatio           ?? null,
        earningsGrowth:    live.earningsGrowth     ?? fallback.earningsGrowth    ?? null,
        futureGrowth:      live.futureGrowth       ?? fallback.futureGrowth      ?? 5,
        socialSentiment:   live.socialSentiment    ?? fallback.socialSentiment   ?? 5,
        newsSentiment:     live.newsSentiment      ?? null,
        targetMeanPrice:   live.targetMeanPrice    ?? null,
        targetHighPrice:   live.targetHighPrice    ?? null,
        targetLowPrice:    live.targetLowPrice     ?? null,
        recommendationKey: live.recommendationKey  ?? null,
        numberOfAnalysts:  live.numberOfAnalysts   ?? null,
        analystBuy:        live.analystBuy         ?? null,
        analystHold:       live.analystHold        ?? null,
        analystSell:       live.analystSell        ?? null,
        rsi:               live.rsi                ?? null,
        sma20:             live.sma20              ?? null,
        sma50:             live.sma50              ?? null,
        sma200:            live.sma200             ?? null,
      };
    }

    if (fallback.currentPrice) {
      const range = fallback.high52Week - fallback.low52Week;
      const socialSentiment = range > 0
        ? Math.max(0, Math.min(10, ((fallback.currentPrice - fallback.low52Week) / range) * 10))
        : fallback.socialSentiment;
      return {
        ticker:            def.ticker,
        companyName:       def.companyName,
        currentPrice:      fallback.currentPrice,
        high52Week:        fallback.high52Week,
        low52Week:         fallback.low52Week,
        marketCap:         fallback.marketCapCr * 1e7,
        marketCapCr:       fallback.marketCapCr,
        peRatio:           fallback.peRatio,
        earningsGrowth:    fallback.earningsGrowth,
        revenueGrowth:     null,
        futureGrowth:      fallback.futureGrowth,
        socialSentiment:   socialSentiment,
        newsSentiment:     null,
        targetMeanPrice:   null,
        targetHighPrice:   null,
        targetLowPrice:    null,
        recommendationKey: null,
        numberOfAnalysts:  null,
        analystBuy:        null,
        analystHold:       null,
        analystSell:       null,
        rsi:               null,
        sma20:             null,
        sma50:             null,
        sma200:            null,
        lastUpdated:       new Date(),
        _isStaticFallback: true,  // live fetch failed — may be delisted
      };
    }

    console.warn(`[rebalanceService] No data for ${def.ticker}, skipping`);
    return null;
  }).filter(Boolean);
};

// ─── selectTopStocks (sync helper kept for backward compat) ───────────────────
const selectTopStocks = (category) => {
  const universe = STOCK_UNIVERSE[category] || STOCK_UNIVERSE.largeCap;
  const isUS = category.startsWith('usa_');
  const investAmount = isUS ? 1000 : 100000;
  const scored = universe.map(def => {
    const fb = STATIC_FALLBACK[def.ticker] || {};
    const stock = { ...def, ...fb };
    const scores = scoreStock(stock);
    return { ...stock, score: scores.total, qualityScores: scores };
  });
  scored.sort((a, b) => b.score - a.score);
  const top15 = scored.slice(0, 15);
  const qualityWeights = computeQualityWeights(top15);
  const quantities = computeQuantities(top15, qualityWeights, investAmount);
  return top15.map((stock, idx) => ({
    ticker:        stock.ticker,
    companyName:   stock.companyName,
    symbol:        stock.ticker,
    currentPrice:  stock.currentPrice,
    buyPrice:      stock.currentPrice,
    high52Week:    stock.high52Week,
    low52Week:     stock.low52Week,
    marketCap:     stock.marketCapCr ? `${stock.marketCapCr} Cr` : null,
    peRatio:       stock.peRatio,
    earningsGrowth: stock.earningsGrowth,
    futureGrowth:  stock.futureGrowth,
    socialSentiment: stock.socialSentiment != null ? Number(stock.socialSentiment.toFixed ? stock.socialSentiment.toFixed(2) : stock.socialSentiment) : null,
    weight:        qualityWeights[idx],
    quantity:      quantities[idx],
    reason:        buildReason(stock, idx + 1, stock.qualityScores),
    status:        'active',
    addedDate:     new Date(),
    score:         stock.score,
    qualityScores: stock.qualityScores,
  }));
};

// ─── Main rebalance function ───────────────────────────────────────────────────
const rebalanceBasket = async (basketId, manualTrigger = false) => {
  try {
    const basket = await Basket.findById(basketId);
    if (!basket) throw new Error('Basket not found');

    // Use stored categoryKey if set (for user-created baskets), else derive from name
    const category     = basket.categoryKey || getCategoryFromName(basket.name);
    const universeDefs = STOCK_UNIVERSE[category] || STOCK_UNIVERSE.largeCap;
    const tickers      = universeDefs.map(d => d.ticker);

    let enrichedStocks;
    try {
      const liveResults = await getEnrichedUniverseData(tickers);
      enrichedStocks    = mergeWithFallback(universeDefs, liveResults);
    } catch (fetchErr) {
      console.warn(`[rebalanceService] Live fetch failed, using full static fallback: ${fetchErr.message}`);
      enrichedStocks = mergeWithFallback(universeDefs, universeDefs.map(() => null));
    }

    const scored = enrichedStocks.map(stock => {
      const scores = scoreStock(stock);
      // Penalize stocks not served by live Yahoo Finance data.
      // _isStooqFallback: Stooq price only (no fundamentals) → -10 pts
      // _isStaticFallback: completely offline/stale data     → -25 pts
      const fallbackPenalty = stock._isStaticFallback ? 25 : stock._isStooqFallback ? 10 : 0;
      if (fallbackPenalty > 0) {
        const reason = stock._isStaticFallback ? 'static fallback, -25pts' : 'Stooq fallback (Yahoo down), -10pts';
        console.warn(`[rebalanceService] ${stock.ticker} using ${reason}`);
      }
      return { ...stock, score: Math.max(0, scores.total - fallbackPenalty), qualityScores: scores };
    });
    scored.sort((a, b) => b.score - a.score);
    const top15 = scored.slice(0, 15);
    const qualityWeights = computeQualityWeights(top15);
    const isUS = category.startsWith('usa_');
    const investAmount = isUS ? 1000 : 100000;
    const quantities = computeQuantities(top15, qualityWeights, investAmount);

    const newStocks = top15.map((stock, idx) => ({
      ticker:            stock.ticker,
      companyName:       stock.companyName,
      symbol:            stock.ticker,
      currentPrice:      stock.currentPrice,
      high52Week:        stock.high52Week,
      low52Week:         stock.low52Week,
      marketCap:         stock.marketCapCr ? `${stock.marketCapCr} Cr` : null,
      peRatio:           stock.peRatio,
      earningsGrowth:    stock.earningsGrowth,
      revenueGrowth:     stock.revenueGrowth,
      futureGrowth:      stock.futureGrowth,
      socialSentiment:   stock.socialSentiment != null ? Number(stock.socialSentiment.toFixed(2)) : null,
      newsSentiment:     stock.newsSentiment ?? null,
      targetMeanPrice:   stock.targetMeanPrice ?? null,
      targetHighPrice:   stock.targetHighPrice ?? null,
      targetLowPrice:    stock.targetLowPrice  ?? null,
      recommendationKey: stock.recommendationKey ?? null,
      numberOfAnalysts:  stock.numberOfAnalysts ?? null,
      analystBuy:        stock.analystBuy ?? null,
      analystHold:       stock.analystHold ?? null,
      analystSell:       stock.analystSell ?? null,
      rsi:               stock.rsi ?? null,
      sma20:             stock.sma20 ?? null,
      sma50:             stock.sma50 ?? null,
      sma200:            stock.sma200 ?? null,
      weight:            qualityWeights[idx],
      quantity:          quantities[idx],
      reason:            buildReason(stock, idx + 1, stock.qualityScores),
      status:            'active',
      buyPrice:          basket.stocks.find(b => b.ticker === stock.ticker)?.buyPrice || stock.currentPrice,
      addedDate:         basket.stocks.find(b => b.ticker === stock.ticker)?.addedDate || new Date(),
      score:             stock.score,
      qualityScores:     stock.qualityScores,
    }));

    const changes = { added: [], removed: [], partialRemoved: [] };
    for (const old of basket.stocks) {
      const newMatch = newStocks.find(s => s.ticker === old.ticker);
      if (!newMatch) {
        changes.removed.push({ ticker: old.ticker, companyName: old.companyName, quantity: old.quantity, buyPrice: old.buyPrice || old.currentPrice, salePrice: old.currentPrice, addedDate: old.addedDate || null });
      } else if (newMatch.quantity < old.quantity) {
        changes.partialRemoved.push({
          ticker:          old.ticker,
          companyName:     old.companyName,
          quantityRemoved: old.quantity - newMatch.quantity,
          quantityKept:    newMatch.quantity,
          buyPrice:        old.buyPrice || old.currentPrice,
          salePrice:       old.currentPrice,
          addedDate:       old.addedDate || null,
          reason:          'Quality score decreased',
        });
      }
    }
    for (const ns of newStocks) {
      if (!basket.stocks.find(s => s.ticker === ns.ticker))
        changes.added.push({
          ticker:      ns.ticker,
          companyName: ns.companyName,
          quantity:    ns.quantity,
          buyPrice:    ns.currentPrice,
          addedDate:   new Date(),
          reason:      ns.reason,
        });
    }

    basket.stocks            = newStocks;
    basket.totalValue        = Math.ceil(newStocks.reduce((sum, s) => sum + ((s.currentPrice || 0) * (s.quantity || 1)), 0));
    basket.minimumInvestment = basket.totalValue;
    basket.lastRebalanceDate = new Date();
    basket.nextRebalanceDate = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);
    await basket.save();

    try {
      await new RebalanceHistory({
        basketId,
        changes,
        reason: manualTrigger ? 'Manual rebalance' : 'Auto rebalance (30-day)',
        manualTrigger,
        emailsSent: 0,
      }).save();
    } catch (e) { console.warn('History save failed:', e.message); }

    if (basket.subscribers?.length) {
      for (const email of basket.subscribers) {
        try { await emailService.sendRebalanceNotification(email, basket, changes); }
        catch (e) { console.warn('Email failed:', e.message); }
      }
    }

    return { success: true, basket, changes, emailsSent: basket.subscribers.length };
  } catch (err) {
    console.error('Rebalance error:', err);
    throw err;
  }
};

const getRebalanceSummary = async (basketId) => {
  const basket = await Basket.findById(basketId);
  let history = [];
  try { history = await RebalanceHistory.find({ basketId }).sort({ createdAt: -1 }).limit(10); }
  catch (e) { console.warn('History fetch failed:', e.message); }
  return {
    basket: {
      name:              basket.name,
      lastRebalanceDate: basket.lastRebalanceDate,
      nextRebalanceDate: basket.nextRebalanceDate,
      minimumInvestment: basket.minimumInvestment,
    },
    recentChanges: history,
  };
};

module.exports = { rebalanceBasket, selectTopStocks, getRebalanceSummary, STATIC_FALLBACK, buildReason, STOCK_UNIVERSE };